#include "jayess_runtime.h"

#include <ctype.h>
#include <stdlib.h>
#include <string.h>

typedef struct jayess_html_parser {
    const char *input;
    size_t length;
    size_t pos;
    const char *error;
} jayess_html_parser;

typedef struct jayess_html_buffer {
    char *data;
    size_t length;
    size_t capacity;
    int failed;
} jayess_html_buffer;

typedef struct jayess_html_selector_step {
    char combinator;
    char *tag_name;
    char *id;
    char *class_name;
    char *attr_name;
    char *attr_value;
    char *pseudo_class;
} jayess_html_selector_step;

typedef struct jayess_html_selector {
    jayess_html_selector_step *steps;
    int count;
} jayess_html_selector;

typedef struct jayess_html_position {
    size_t offset;
    int line;
    int column;
} jayess_html_position;

static void jayess_html_fail(jayess_html_parser *parser, const char *message) {
    if (parser->error == NULL) {
        parser->error = message;
    }
}

static int jayess_html_has_prefix(jayess_html_parser *parser, const char *text) {
    size_t prefix_length = strlen(text);
    if (parser->pos + prefix_length > parser->length) {
        return 0;
    }
    return strncmp(parser->input + parser->pos, text, prefix_length) == 0;
}

static int jayess_html_has_prefix_ci(jayess_html_parser *parser, const char *text) {
    size_t prefix_length = strlen(text);
    size_t index;
    if (parser->pos + prefix_length > parser->length) {
        return 0;
    }
    for (index = 0; index < prefix_length; index++) {
        if (tolower((unsigned char) parser->input[parser->pos + index]) != tolower((unsigned char) text[index])) {
            return 0;
        }
    }
    return 1;
}

static int jayess_html_peek(jayess_html_parser *parser) {
    if (parser->pos >= parser->length) {
        return -1;
    }
    return (unsigned char) parser->input[parser->pos];
}

static void jayess_html_skip_ws(jayess_html_parser *parser) {
    while (parser->pos < parser->length && isspace((unsigned char) parser->input[parser->pos])) {
        parser->pos++;
    }
}

static int jayess_html_is_name_char(int ch) {
    return isalnum((unsigned char) ch) || ch == '-' || ch == '_' || ch == ':' || ch == '.';
}

static char *jayess_html_strdup(const char *text) {
    size_t length;
    char *copy;
    if (text == NULL) {
        return NULL;
    }
    length = strlen(text);
    copy = (char *) malloc(length + 1);
    if (copy == NULL) {
        return NULL;
    }
    memcpy(copy, text, length + 1);
    return copy;
}

static char *jayess_html_copy_range(const char *input, size_t start, size_t end) {
    size_t length = end > start ? end - start : 0;
    char *text = (char *) malloc(length + 1);
    if (text == NULL) {
        return NULL;
    }
    if (length > 0) {
        memcpy(text, input + start, length);
    }
    text[length] = '\0';
    return text;
}

static char *jayess_html_parse_name(jayess_html_parser *parser) {
    size_t start = parser->pos;
    while (parser->pos < parser->length && jayess_html_is_name_char((unsigned char) parser->input[parser->pos])) {
        parser->pos++;
    }
    if (parser->pos == start) {
        return NULL;
    }
    return jayess_html_copy_range(parser->input, start, parser->pos);
}

static char *jayess_html_parse_attr_value(jayess_html_parser *parser) {
    int quote = jayess_html_peek(parser);
    size_t start;
    if (quote == '"' || quote == '\'') {
        parser->pos++;
        start = parser->pos;
        while (parser->pos < parser->length && parser->input[parser->pos] != quote) {
            parser->pos++;
        }
        if (parser->pos >= parser->length) {
            jayess_html_fail(parser, "unterminated HTML attribute value");
            return NULL;
        }
        {
            char *value = jayess_html_copy_range(parser->input, start, parser->pos);
            parser->pos++;
            return value;
        }
    }
    start = parser->pos;
    while (parser->pos < parser->length) {
        int ch = jayess_html_peek(parser);
        if (isspace((unsigned char) ch) || ch == '>' || (ch == '/' && parser->pos + 1 < parser->length && parser->input[parser->pos + 1] == '>')) {
            break;
        }
        parser->pos++;
    }
    return jayess_html_copy_range(parser->input, start, parser->pos);
}

static jayess_html_position jayess_html_position_for(jayess_html_parser *parser, size_t offset) {
    jayess_html_position position;
    size_t index;
    position.offset = offset;
    position.line = 1;
    position.column = 1;
    for (index = 0; index < offset && index < parser->length; index++) {
        if (parser->input[index] == '\n') {
            position.line++;
            position.column = 1;
        } else {
            position.column++;
        }
    }
    return position;
}

static jayess_value *jayess_html_position_value(jayess_html_position position) {
    jayess_object *value = jayess_object_new();
    jayess_object_set_value(value, "offset", jayess_value_from_number((double) position.offset));
    jayess_object_set_value(value, "line", jayess_value_from_number((double) position.line));
    jayess_object_set_value(value, "column", jayess_value_from_number((double) position.column));
    return jayess_value_from_object(value);
}

static void jayess_html_set_span(jayess_value *node, jayess_html_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_object *span = jayess_object_new();
    jayess_object_set_value(span, "start", jayess_html_position_value(jayess_html_position_for(parser, start_offset)));
    jayess_object_set_value(span, "end", jayess_html_position_value(jayess_html_position_for(parser, end_offset)));
    jayess_value_set_member(node, "span", jayess_value_from_object(span));
}

static jayess_value *jayess_html_make_token(const char *type, jayess_html_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_object *token = jayess_object_new();
    jayess_object_set_value(token, "type", jayess_value_from_string(type));
    jayess_object_set_value(token, "span", jayess_value_undefined());
    {
        jayess_value *value = jayess_value_from_object(token);
        jayess_html_set_span(value, parser, start_offset, end_offset);
        return value;
    }
}

static jayess_value *jayess_html_make_document_like(const char *type, jayess_array *children) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string(type));
    jayess_object_set_value(node, "children", jayess_value_from_array(children));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_html_make_text(const char *value) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("text"));
    jayess_object_set_value(node, "value", jayess_value_from_string(value));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_html_make_comment(const char *value) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("comment"));
    jayess_object_set_value(node, "value", jayess_value_from_string(value));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_html_make_doctype(const char *value) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("doctype"));
    jayess_object_set_value(node, "value", jayess_value_from_string(value));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_html_make_element(const char *tag_name, jayess_object *attributes, jayess_array *attribute_order, jayess_array *children, int self_closing) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("element"));
    jayess_object_set_value(node, "tagName", jayess_value_from_string(tag_name));
    jayess_object_set_value(node, "attributes", jayess_value_from_object(attributes));
    jayess_object_set_value(node, "attributeOrder", jayess_value_from_array(attribute_order));
    jayess_object_set_value(node, "children", jayess_value_from_array(children));
    jayess_object_set_value(node, "selfClosing", jayess_value_from_bool(self_closing));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_html_make_start_tag_token(
    const char *tag_name,
    jayess_object *attributes,
    jayess_array *attribute_order,
    int self_closing,
    jayess_html_parser *parser,
    size_t start_offset,
    size_t end_offset
) {
    jayess_value *token = jayess_html_make_token("startTag", parser, start_offset, end_offset);
    jayess_value_set_member(token, "tagName", jayess_value_from_string(tag_name));
    jayess_value_set_member(token, "attributes", jayess_value_from_object(attributes));
    jayess_value_set_member(token, "attributeOrder", jayess_value_from_array(attribute_order));
    jayess_value_set_member(token, "selfClosing", jayess_value_from_bool(self_closing));
    return token;
}

static jayess_value *jayess_html_make_end_tag_token(const char *tag_name, jayess_html_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_value *token = jayess_html_make_token("endTag", parser, start_offset, end_offset);
    jayess_value_set_member(token, "tagName", jayess_value_from_string(tag_name));
    return token;
}

static jayess_value *jayess_html_make_text_token(const char *value, jayess_html_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_value *token = jayess_html_make_token("text", parser, start_offset, end_offset);
    jayess_value_set_member(token, "value", jayess_value_from_string(value));
    return token;
}

static jayess_value *jayess_html_make_comment_token(const char *value, jayess_html_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_value *token = jayess_html_make_token("comment", parser, start_offset, end_offset);
    jayess_value_set_member(token, "value", jayess_value_from_string(value));
    return token;
}

static jayess_value *jayess_html_make_doctype_token(const char *value, jayess_html_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_value *token = jayess_html_make_token("doctype", parser, start_offset, end_offset);
    jayess_value_set_member(token, "value", jayess_value_from_string(value));
    return token;
}

static const char *jayess_html_node_type(jayess_value *node) {
    return jayess_value_as_string(jayess_value_get_member(node, "type"));
}

static int jayess_html_node_has_children(jayess_value *node) {
    const char *type = jayess_html_node_type(node);
    return type != NULL && (strcmp(type, "document") == 0 || strcmp(type, "fragment") == 0 || strcmp(type, "element") == 0);
}

static jayess_array *jayess_html_expect_children(jayess_value *node, const char *context) {
    if (!jayess_html_node_has_children(node)) {
        jayess_throw_named_error("HTMLNodeError", context);
        return NULL;
    }
    return jayess_value_as_array(jayess_value_get_member(node, "children"));
}

static int jayess_html_is_element(jayess_value *node) {
    const char *type = jayess_html_node_type(node);
    return type != NULL && strcmp(type, "element") == 0;
}

static const char *jayess_html_element_attribute(jayess_value *node, const char *name) {
    jayess_object *attributes;
    jayess_value *value;
    if (!jayess_html_is_element(node)) {
        return NULL;
    }
    attributes = jayess_value_as_object(jayess_value_get_member(node, "attributes"));
    if (attributes == NULL) {
        return NULL;
    }
    value = jayess_object_get(attributes, name);
    if (value == NULL || jayess_value_kind_of(value) == JAYESS_VALUE_UNDEFINED) {
        return NULL;
    }
    if (jayess_value_kind_of(value) == JAYESS_VALUE_BOOL && jayess_value_as_bool(value)) {
        return "";
    }
    return jayess_value_as_string(value);
}

static int jayess_html_has_class_name(jayess_value *node, const char *class_name) {
    const char *classes = jayess_html_element_attribute(node, "class");
    size_t target_length;
    const char *cursor;
    if (classes == NULL || class_name == NULL) {
        return 0;
    }
    target_length = strlen(class_name);
    cursor = classes;
    while (*cursor != '\0') {
        const char *start;
        size_t length;
        while (*cursor != '\0' && isspace((unsigned char) *cursor)) {
            cursor++;
        }
        start = cursor;
        while (*cursor != '\0' && !isspace((unsigned char) *cursor)) {
            cursor++;
        }
        length = (size_t) (cursor - start);
        if (length == target_length && strncmp(start, class_name, length) == 0) {
            return 1;
        }
    }
    return 0;
}

static int jayess_html_selector_is_name_char(int ch) {
    return isalnum((unsigned char) ch) || ch == '-' || ch == '_' || ch == '.' || ch == '*';
}

static char *jayess_html_selector_parse_name(const char *input, size_t length, size_t *pos) {
    size_t start = *pos;
    while (*pos < length && jayess_html_selector_is_name_char((unsigned char) input[*pos])) {
        (*pos)++;
    }
    if (*pos == start) {
        return NULL;
    }
    return jayess_html_copy_range(input, start, *pos);
}

static char *jayess_html_selector_parse_attr_value(const char *input, size_t length, size_t *pos) {
    int quote;
    size_t start;
    if (*pos >= length) {
        return NULL;
    }
    quote = (unsigned char) input[*pos];
    if (quote == '"' || quote == '\'') {
        (*pos)++;
        start = *pos;
        while (*pos < length && input[*pos] != quote) {
            (*pos)++;
        }
        if (*pos >= length) {
            return NULL;
        }
        {
            char *value = jayess_html_copy_range(input, start, *pos);
            (*pos)++;
            return value;
        }
    }
    start = *pos;
    while (*pos < length && input[*pos] != ']' && !isspace((unsigned char) input[*pos]) && input[*pos] != '>') {
        (*pos)++;
    }
    return jayess_html_copy_range(input, start, *pos);
}

static void jayess_html_selector_free(jayess_html_selector *selector) {
    int index;
    if (selector == NULL || selector->steps == NULL) {
        return;
    }
    for (index = 0; index < selector->count; index++) {
        free(selector->steps[index].tag_name);
        free(selector->steps[index].id);
        free(selector->steps[index].class_name);
        free(selector->steps[index].attr_name);
        free(selector->steps[index].attr_value);
        free(selector->steps[index].pseudo_class);
    }
    free(selector->steps);
    selector->steps = NULL;
    selector->count = 0;
}

static int jayess_html_selector_append_step(jayess_html_selector *selector, jayess_html_selector_step step) {
    jayess_html_selector_step *grown = (jayess_html_selector_step *) realloc(selector->steps, sizeof(jayess_html_selector_step) * (size_t) (selector->count + 1));
    if (grown == NULL) {
        return 0;
    }
    selector->steps = grown;
    selector->steps[selector->count] = step;
    selector->count++;
    return 1;
}

static int jayess_html_parse_selector(const char *input, jayess_html_selector *selector) {
    size_t length = strlen(input);
    size_t pos = 0;
    char pending_combinator = 0;
    selector->steps = NULL;
    selector->count = 0;
    while (pos < length) {
        jayess_html_selector_step step;
        int saw_whitespace = 0;
        memset(&step, 0, sizeof(step));
        while (pos < length && isspace((unsigned char) input[pos])) {
            saw_whitespace = 1;
            pos++;
        }
        if (pos >= length) {
            break;
        }
        if (input[pos] == '>') {
            pending_combinator = '>';
            pos++;
            continue;
        }
        step.combinator = pending_combinator != 0 ? pending_combinator : (selector->count > 0 && saw_whitespace ? ' ' : 0);
        pending_combinator = 0;
        while (pos < length) {
            if (input[pos] == '#') {
                pos++;
                step.id = jayess_html_selector_parse_name(input, length, &pos);
                if (step.id == NULL) {
                    jayess_html_selector_free(selector);
                    return 0;
                }
                continue;
            }
            if (input[pos] == '.') {
                pos++;
                step.class_name = jayess_html_selector_parse_name(input, length, &pos);
                if (step.class_name == NULL) {
                    jayess_html_selector_free(selector);
                    return 0;
                }
                continue;
            }
            if (input[pos] == '[') {
                pos++;
                while (pos < length && isspace((unsigned char) input[pos])) {
                    pos++;
                }
                step.attr_name = jayess_html_selector_parse_name(input, length, &pos);
                if (step.attr_name == NULL) {
                    jayess_html_selector_free(selector);
                    return 0;
                }
                while (pos < length && isspace((unsigned char) input[pos])) {
                    pos++;
                }
                if (pos < length && input[pos] == '=') {
                    pos++;
                    while (pos < length && isspace((unsigned char) input[pos])) {
                        pos++;
                    }
                    step.attr_value = jayess_html_selector_parse_attr_value(input, length, &pos);
                    if (step.attr_value == NULL) {
                        jayess_html_selector_free(selector);
                        return 0;
                    }
                }
                while (pos < length && isspace((unsigned char) input[pos])) {
                    pos++;
                }
                if (pos >= length || input[pos] != ']') {
                    jayess_html_selector_free(selector);
                    return 0;
                }
                pos++;
                continue;
            }
            if (input[pos] == ':') {
                pos++;
                step.pseudo_class = jayess_html_selector_parse_name(input, length, &pos);
                if (step.pseudo_class == NULL) {
                    jayess_html_selector_free(selector);
                    return 0;
                }
                if (
                    strcmp(step.pseudo_class, "first-child") != 0 &&
                    strcmp(step.pseudo_class, "last-child") != 0 &&
                    strcmp(step.pseudo_class, "empty") != 0
                ) {
                    jayess_html_selector_free(selector);
                    return 0;
                }
                continue;
            }
            if (input[pos] == '>' || isspace((unsigned char) input[pos])) {
                break;
            }
            if (step.tag_name == NULL) {
                step.tag_name = jayess_html_selector_parse_name(input, length, &pos);
                if (step.tag_name == NULL) {
                    jayess_html_selector_free(selector);
                    return 0;
                }
                continue;
            }
            jayess_html_selector_free(selector);
            return 0;
        }
        if (step.tag_name == NULL && step.id == NULL && step.class_name == NULL && step.attr_name == NULL && step.pseudo_class == NULL) {
            jayess_html_selector_free(selector);
            return 0;
        }
        if (!jayess_html_selector_append_step(selector, step)) {
            jayess_html_selector_free(selector);
            return 0;
        }
    }
    return selector->count > 0;
}

static int jayess_html_matches_pseudo_class(jayess_value **ancestors, int node_index, const char *pseudo_class) {
    jayess_value *node;
    jayess_value *parent;
    jayess_array *children;
    int length;
    if (pseudo_class == NULL) {
        return 1;
    }
    node = ancestors[node_index];
    if (strcmp(pseudo_class, "empty") == 0) {
        jayess_array *node_children = jayess_value_as_array(jayess_value_get_member(node, "children"));
        return node_children == NULL || jayess_array_length(node_children) == 0;
    }
    if (node_index <= 0) {
        return 0;
    }
    parent = ancestors[node_index - 1];
    children = jayess_value_as_array(jayess_value_get_member(parent, "children"));
    if (children == NULL) {
        return 0;
    }
    length = jayess_array_length(children);
    if (strcmp(pseudo_class, "first-child") == 0) {
        return length > 0 && jayess_array_get(children, 0) == node;
    }
    if (strcmp(pseudo_class, "last-child") == 0) {
        return length > 0 && jayess_array_get(children, length - 1) == node;
    }
    return 0;
}

static int jayess_html_matches_selector_step(jayess_value **ancestors, int node_index, jayess_html_selector_step *step) {
    const char *tag_name;
    const char *id_value;
    const char *attr_value;
    jayess_value *node = ancestors[node_index];
    if (!jayess_html_is_element(node)) {
        return 0;
    }
    if (step->tag_name != NULL && strcmp(step->tag_name, "*") != 0) {
        tag_name = jayess_value_as_string(jayess_value_get_member(node, "tagName"));
        if (tag_name == NULL || strcmp(tag_name, step->tag_name) != 0) {
            return 0;
        }
    }
    if (step->id != NULL) {
        id_value = jayess_html_element_attribute(node, "id");
        if (id_value == NULL || strcmp(id_value, step->id) != 0) {
            return 0;
        }
    }
    if (step->class_name != NULL && !jayess_html_has_class_name(node, step->class_name)) {
        return 0;
    }
    if (step->attr_name != NULL) {
        attr_value = jayess_html_element_attribute(node, step->attr_name);
        if (attr_value == NULL) {
            return 0;
        }
        if (step->attr_value != NULL && strcmp(attr_value, step->attr_value) != 0) {
            return 0;
        }
    }
    if (!jayess_html_matches_pseudo_class(ancestors, node_index, step->pseudo_class)) {
        return 0;
    }
    return 1;
}

static int jayess_html_matches_selector_steps(jayess_value **ancestors, int depth, jayess_html_selector *selector, int step_index, int node_index) {
    int search_index;
    if (node_index < 0) {
        return 0;
    }
    if (!jayess_html_matches_selector_step(ancestors, node_index, &selector->steps[step_index])) {
        return 0;
    }
    if (step_index == 0) {
        return 1;
    }
    if (selector->steps[step_index].combinator == '>') {
        return jayess_html_matches_selector_steps(ancestors, depth, selector, step_index - 1, node_index - 1);
    }
    for (search_index = node_index - 1; search_index >= 0; search_index--) {
        if (jayess_html_matches_selector_steps(ancestors, depth, selector, step_index - 1, search_index)) {
            return 1;
        }
    }
    return 0;
}

static void jayess_html_query_selector_collect(jayess_value *node, jayess_html_selector *selector, jayess_array *result, jayess_value **ancestors, int depth) {
    int index;
    jayess_array *children;
    ancestors[depth] = node;
    if (jayess_html_matches_selector_steps(ancestors, depth + 1, selector, selector->count - 1, depth)) {
        jayess_array_push_value(result, node);
    }
    if (!jayess_html_node_has_children(node)) {
        return;
    }
    children = jayess_value_as_array(jayess_value_get_member(node, "children"));
    if (children == NULL) {
        return;
    }
    for (index = 0; index < jayess_array_length(children); index++) {
        jayess_html_query_selector_collect(jayess_array_get(children, index), selector, result, ancestors, depth + 1);
    }
}

static int jayess_html_attribute_order_contains(jayess_array *attribute_order, const char *name) {
    int index;
    for (index = 0; index < jayess_array_length(attribute_order); index++) {
        const char *existing = jayess_value_as_string(jayess_array_get(attribute_order, index));
        if (existing != NULL && strcmp(existing, name) == 0) {
            return 1;
        }
    }
    return 0;
}

static jayess_array *jayess_html_remove_index(jayess_array *source, int remove_index) {
    jayess_array *result = jayess_array_new();
    int index;
    for (index = 0; index < jayess_array_length(source); index++) {
        if (index != remove_index) {
            jayess_array_push_value(result, jayess_array_get(source, index));
        }
    }
    return result;
}

static jayess_object *jayess_html_clone_attributes(jayess_object *attributes, jayess_array *attribute_order) {
    jayess_object *clone = jayess_object_new();
    int index;
    for (index = 0; index < jayess_array_length(attribute_order); index++) {
        const char *name = jayess_value_as_string(jayess_array_get(attribute_order, index));
        if (name != NULL) {
            jayess_object_set_value(clone, name, jayess_object_get(attributes, name));
        }
    }
    return clone;
}

static jayess_value *jayess_html_clone_node_value(jayess_value *node);

static jayess_array *jayess_html_clone_children(jayess_array *children) {
    jayess_array *clone = jayess_array_new();
    int index;
    for (index = 0; index < jayess_array_length(children); index++) {
        jayess_array_push_value(clone, jayess_html_clone_node_value(jayess_array_get(children, index)));
    }
    return clone;
}

static jayess_value *jayess_html_clone_node_value(jayess_value *node) {
    const char *type = jayess_html_node_type(node);
    if (type == NULL) {
        return jayess_value_undefined();
    }
    if (strcmp(type, "text") == 0) {
        return jayess_html_make_text(jayess_value_as_string(jayess_value_get_member(node, "value")));
    }
    if (strcmp(type, "comment") == 0) {
        return jayess_html_make_comment(jayess_value_as_string(jayess_value_get_member(node, "value")));
    }
    if (strcmp(type, "document") == 0 || strcmp(type, "fragment") == 0) {
        return jayess_html_make_document_like(type, jayess_html_clone_children(jayess_value_as_array(jayess_value_get_member(node, "children"))));
    }
    if (strcmp(type, "element") == 0) {
        const char *tag_name = jayess_value_as_string(jayess_value_get_member(node, "tagName"));
        jayess_object *attributes = jayess_value_as_object(jayess_value_get_member(node, "attributes"));
        jayess_array *attribute_order = jayess_value_as_array(jayess_value_get_member(node, "attributeOrder"));
        jayess_array *children = jayess_value_as_array(jayess_value_get_member(node, "children"));
        int self_closing = jayess_value_as_bool(jayess_value_get_member(node, "selfClosing"));
        jayess_array *attribute_order_clone = jayess_array_new();
        int index;
        for (index = 0; index < jayess_array_length(attribute_order); index++) {
            jayess_array_push_value(attribute_order_clone, jayess_array_get(attribute_order, index));
        }
        return jayess_html_make_element(
            tag_name != NULL ? tag_name : "",
            jayess_html_clone_attributes(attributes, attribute_order),
            attribute_order_clone,
            jayess_html_clone_children(children),
            self_closing
        );
    }
    return jayess_value_undefined();
}

static void jayess_html_walk_collect(jayess_value *node, jayess_array *result) {
    int index;
    jayess_array *children;
    jayess_array_push_value(result, node);
    if (!jayess_html_node_has_children(node)) {
        return;
    }
    children = jayess_value_as_array(jayess_value_get_member(node, "children"));
    if (children == NULL) {
        return;
    }
    for (index = 0; index < jayess_array_length(children); index++) {
        jayess_html_walk_collect(jayess_array_get(children, index), result);
    }
}

static void jayess_html_find_by_tag_collect(jayess_value *node, const char *tag_name, jayess_array *result) {
    int index;
    jayess_array *children;
    if (jayess_html_is_element(node)) {
        const char *node_tag = jayess_value_as_string(jayess_value_get_member(node, "tagName"));
        if (node_tag != NULL && strcmp(node_tag, tag_name) == 0) {
            jayess_array_push_value(result, node);
        }
    }
    if (!jayess_html_node_has_children(node)) {
        return;
    }
    children = jayess_value_as_array(jayess_value_get_member(node, "children"));
    if (children == NULL) {
        return;
    }
    for (index = 0; index < jayess_array_length(children); index++) {
        jayess_html_find_by_tag_collect(jayess_array_get(children, index), tag_name, result);
    }
}

static jayess_array *jayess_html_parse_children(jayess_html_parser *parser, const char *closing_tag);

static void jayess_html_free_partial_object(jayess_object *object) {
    if (object != NULL) {
        jayess_object_free_unshared(object);
    }
}

static void jayess_html_free_partial_array(jayess_array *array) {
    if (array != NULL) {
        jayess_array_free_unshared(array);
    }
}

static jayess_value *jayess_html_parse_element(jayess_html_parser *parser) {
    char *tag_name;
    jayess_object *attributes;
    jayess_array *attribute_order;
    jayess_array *children;
    int self_closing = 0;
    size_t start_offset = parser->pos;
    if (jayess_html_peek(parser) != '<') {
        jayess_html_fail(parser, "expected HTML element");
        return jayess_value_undefined();
    }
    parser->pos++;
    tag_name = jayess_html_parse_name(parser);
    if (tag_name == NULL) {
        jayess_html_fail(parser, "expected HTML tag name");
        return jayess_value_undefined();
    }
    attributes = jayess_object_new();
    attribute_order = jayess_array_new();
    while (parser->pos < parser->length) {
        char *attr_name;
        char *attr_value;
        jayess_html_skip_ws(parser);
        if (jayess_html_has_prefix(parser, "/>")) {
            self_closing = 1;
            parser->pos += 2;
            break;
        }
        if (jayess_html_peek(parser) == '>') {
            parser->pos++;
            break;
        }
        attr_name = jayess_html_parse_name(parser);
        if (attr_name == NULL) {
            jayess_html_free_partial_object(attributes);
            jayess_html_free_partial_array(attribute_order);
            free(tag_name);
            jayess_html_fail(parser, "expected HTML attribute name");
            return jayess_value_undefined();
        }
        jayess_array_push_value(attribute_order, jayess_value_from_string(attr_name));
        jayess_html_skip_ws(parser);
        if (jayess_html_peek(parser) == '=') {
            parser->pos++;
            jayess_html_skip_ws(parser);
            attr_value = jayess_html_parse_attr_value(parser);
            if (attr_value == NULL) {
                free(attr_name);
                jayess_html_free_partial_object(attributes);
                jayess_html_free_partial_array(attribute_order);
                free(tag_name);
                return jayess_value_undefined();
            }
            jayess_object_set_value(attributes, attr_name, jayess_value_from_string(attr_value));
            free(attr_value);
        } else {
            jayess_object_set_value(attributes, attr_name, jayess_value_from_bool(1));
        }
        free(attr_name);
    }
    children = self_closing ? jayess_array_new() : jayess_html_parse_children(parser, tag_name);
    if (parser->error != NULL || jayess_has_exception()) {
        jayess_html_free_partial_object(attributes);
        jayess_html_free_partial_array(attribute_order);
        jayess_html_free_partial_array(children);
        free(tag_name);
        return jayess_value_undefined();
    }
    {
        jayess_value *element = jayess_html_make_element(tag_name, attributes, attribute_order, children, self_closing);
        jayess_html_set_span(element, parser, start_offset, parser->pos);
        free(tag_name);
        return element;
    }
}

static jayess_array *jayess_html_parse_children(jayess_html_parser *parser, const char *closing_tag) {
    jayess_array *children = jayess_array_new();
    while (parser->pos < parser->length) {
        if (closing_tag != NULL && jayess_html_has_prefix(parser, "</")) {
            parser->pos += 2;
            jayess_html_skip_ws(parser);
            {
                char *name = jayess_html_parse_name(parser);
                jayess_html_skip_ws(parser);
                if (jayess_html_peek(parser) == '>') {
                    parser->pos++;
                }
                if (name != NULL) {
                    free(name);
                }
            }
            return children;
        }
        if (jayess_html_has_prefix(parser, "<!--")) {
            size_t start;
            size_t end;
            char *comment_text;
            size_t comment_start = parser->pos;
            parser->pos += 4;
            start = parser->pos;
            while (parser->pos + 2 < parser->length && !jayess_html_has_prefix(parser, "-->")) {
                parser->pos++;
            }
            if (!jayess_html_has_prefix(parser, "-->")) {
                jayess_html_fail(parser, "unterminated HTML comment");
                return children;
            }
            end = parser->pos;
            comment_text = jayess_html_copy_range(parser->input, start, end);
            parser->pos += 3;
            {
                jayess_value *comment_node = jayess_html_make_comment(comment_text);
                jayess_html_set_span(comment_node, parser, comment_start, parser->pos);
                jayess_array_push_value(children, comment_node);
            }
            free(comment_text);
            continue;
        }
        if (jayess_html_has_prefix_ci(parser, "<!DOCTYPE")) {
            size_t value_start;
            size_t value_end;
            char *doctype_text;
            size_t doctype_start = parser->pos;
            parser->pos += 9;
            jayess_html_skip_ws(parser);
            value_start = parser->pos;
            while (parser->pos < parser->length && jayess_html_peek(parser) != '>') {
                parser->pos++;
            }
            if (jayess_html_peek(parser) != '>') {
                jayess_html_fail(parser, "unterminated HTML doctype");
                return children;
            }
            value_end = parser->pos;
            doctype_text = jayess_html_copy_range(parser->input, value_start, value_end);
            parser->pos++;
            {
                jayess_value *doctype_node = jayess_html_make_doctype(doctype_text != NULL ? doctype_text : "");
                jayess_html_set_span(doctype_node, parser, doctype_start, parser->pos);
                jayess_array_push_value(children, doctype_node);
            }
            free(doctype_text);
            continue;
        }
        if (jayess_html_peek(parser) == '<') {
            jayess_array_push_value(children, jayess_html_parse_element(parser));
            if (jayess_has_exception() || parser->error != NULL) {
                return children;
            }
            continue;
        }
        {
            size_t start = parser->pos;
            char *text;
            while (parser->pos < parser->length && parser->input[parser->pos] != '<') {
                parser->pos++;
            }
            text = jayess_html_copy_range(parser->input, start, parser->pos);
            if (text != NULL && text[0] != '\0') {
                jayess_value *text_node = jayess_html_make_text(text);
                jayess_html_set_span(text_node, parser, start, parser->pos);
                jayess_array_push_value(children, text_node);
            }
            if (text != NULL) {
                free(text);
            }
        }
    }
    return children;
}

static void jayess_html_buffer_append_bytes(jayess_html_buffer *buffer, const char *text, size_t length) {
    size_t required;
    char *grown;
    if (buffer->failed || text == NULL || length == 0) {
        return;
    }
    required = buffer->length + length + 1;
    if (required > buffer->capacity) {
        size_t next_capacity = buffer->capacity == 0 ? 64 : buffer->capacity;
        while (next_capacity < required) {
            next_capacity *= 2;
        }
        grown = (char *) realloc(buffer->data, next_capacity);
        if (grown == NULL) {
            buffer->failed = 1;
            return;
        }
        buffer->data = grown;
        buffer->capacity = next_capacity;
    }
    memcpy(buffer->data + buffer->length, text, length);
    buffer->length += length;
    buffer->data[buffer->length] = '\0';
}

static void jayess_html_buffer_append_cstr(jayess_html_buffer *buffer, const char *text) {
    if (text == NULL) {
        return;
    }
    jayess_html_buffer_append_bytes(buffer, text, strlen(text));
}

static int jayess_html_serialize_preserve_comments(jayess_value *options) {
    jayess_value *comments_value;
    if (options == NULL || jayess_value_kind_of(options) == JAYESS_VALUE_UNDEFINED || jayess_value_kind_of(options) == JAYESS_VALUE_NULL) {
        return 1;
    }
    comments_value = jayess_value_get_member(options, "comments");
    if (comments_value == NULL || jayess_value_kind_of(comments_value) == JAYESS_VALUE_UNDEFINED) {
        return 1;
    }
    return jayess_value_as_bool(comments_value);
}

static int jayess_html_serialize_pretty(jayess_value *options) {
    jayess_value *pretty_value;
    if (options == NULL || jayess_value_kind_of(options) == JAYESS_VALUE_UNDEFINED || jayess_value_kind_of(options) == JAYESS_VALUE_NULL) {
        return 0;
    }
    pretty_value = jayess_value_get_member(options, "pretty");
    if (pretty_value == NULL || jayess_value_kind_of(pretty_value) == JAYESS_VALUE_UNDEFINED) {
        return 0;
    }
    return jayess_value_as_bool(pretty_value);
}

static int jayess_html_serialize_minify(jayess_value *options) {
    jayess_value *minify_value;
    if (options == NULL || jayess_value_kind_of(options) == JAYESS_VALUE_UNDEFINED || jayess_value_kind_of(options) == JAYESS_VALUE_NULL) {
        return 0;
    }
    minify_value = jayess_value_get_member(options, "minify");
    if (minify_value == NULL || jayess_value_kind_of(minify_value) == JAYESS_VALUE_UNDEFINED) {
        return 0;
    }
    return jayess_value_as_bool(minify_value);
}

static void jayess_html_buffer_indent(jayess_html_buffer *buffer, int depth) {
    int index;
    for (index = 0; index < depth; index++) {
        jayess_html_buffer_append_cstr(buffer, "  ");
    }
}

static int jayess_html_children_are_inline_text(jayess_array *children) {
    int index;
    if (children == NULL || jayess_array_length(children) == 0) {
        return 1;
    }
    for (index = 0; index < jayess_array_length(children); index++) {
        jayess_value *child = jayess_array_get(children, index);
        const char *type = jayess_value_as_string(jayess_value_get_member(child, "type"));
        if (type == NULL || strcmp(type, "text") != 0) {
            return 0;
        }
    }
    return 1;
}

static void jayess_html_serialize_value(jayess_value *node, jayess_html_buffer *buffer, int preserve_comments, int pretty, int depth);

static void jayess_html_serialize_children(jayess_value *node, jayess_html_buffer *buffer, int preserve_comments, int pretty, int depth) {
    jayess_value *children_value = jayess_value_get_member(node, "children");
    jayess_array *children = jayess_value_as_array(children_value);
    int index;
    if (children == NULL) {
        return;
    }
    for (index = 0; index < jayess_array_length(children); index++) {
        jayess_html_serialize_value(jayess_array_get(children, index), buffer, preserve_comments, pretty, depth);
    }
}

static void jayess_html_serialize_attribute(jayess_html_buffer *buffer, const char *name, jayess_value *value) {
    jayess_html_buffer_append_cstr(buffer, " ");
    jayess_html_buffer_append_cstr(buffer, name);
    if (jayess_value_kind_of(value) == JAYESS_VALUE_BOOL && jayess_value_as_bool(value)) {
        return;
    }
    jayess_html_buffer_append_cstr(buffer, "=\"");
    if (jayess_value_kind_of(value) == JAYESS_VALUE_STRING) {
        jayess_html_buffer_append_cstr(buffer, jayess_value_as_string(value));
    } else {
        char *text = jayess_value_to_string_copy(value);
        if (text != NULL) {
            jayess_html_buffer_append_cstr(buffer, text);
            jayess_string_free(text);
        }
    }
    jayess_html_buffer_append_cstr(buffer, "\"");
}

static void jayess_html_serialize_element(jayess_value *node, jayess_html_buffer *buffer, int preserve_comments, int pretty, int depth) {
    const char *tag_name = jayess_value_as_string(jayess_value_get_member(node, "tagName"));
    jayess_object *attributes = jayess_value_as_object(jayess_value_get_member(node, "attributes"));
    jayess_array *attribute_order = jayess_value_as_array(jayess_value_get_member(node, "attributeOrder"));
    jayess_array *children = jayess_value_as_array(jayess_value_get_member(node, "children"));
    int self_closing = jayess_value_as_bool(jayess_value_get_member(node, "selfClosing"));
    int index;
    jayess_html_buffer_append_cstr(buffer, "<");
    jayess_html_buffer_append_cstr(buffer, tag_name != NULL ? tag_name : "");
    if (attribute_order != NULL && attributes != NULL) {
        for (index = 0; index < jayess_array_length(attribute_order); index++) {
            jayess_value *name_value = jayess_array_get(attribute_order, index);
            const char *name = jayess_value_as_string(name_value);
            if (name != NULL) {
                jayess_html_serialize_attribute(buffer, name, jayess_object_get(attributes, name));
            }
        }
    }
    if (self_closing && (children == NULL || jayess_array_length(children) == 0)) {
        jayess_html_buffer_append_cstr(buffer, "/>");
        return;
    }
    jayess_html_buffer_append_cstr(buffer, ">");
    if (pretty && !jayess_html_children_are_inline_text(children) && children != NULL && jayess_array_length(children) > 0) {
        int emitted_child = 0;
        for (index = 0; index < jayess_array_length(children); index++) {
            jayess_value *child = jayess_array_get(children, index);
            const char *child_type = jayess_value_as_string(jayess_value_get_member(child, "type"));
            if (!preserve_comments && child_type != NULL && strcmp(child_type, "comment") == 0) {
                continue;
            }
            jayess_html_buffer_append_cstr(buffer, "\n");
            jayess_html_buffer_indent(buffer, depth + 1);
            jayess_html_serialize_value(child, buffer, preserve_comments, pretty, depth + 1);
            emitted_child = 1;
        }
        if (emitted_child) {
            jayess_html_buffer_append_cstr(buffer, "\n");
            jayess_html_buffer_indent(buffer, depth);
        }
    } else {
        jayess_html_serialize_children(node, buffer, preserve_comments, pretty, depth + 1);
    }
    jayess_html_buffer_append_cstr(buffer, "</");
    jayess_html_buffer_append_cstr(buffer, tag_name != NULL ? tag_name : "");
    jayess_html_buffer_append_cstr(buffer, ">");
}

static void jayess_html_serialize_value(jayess_value *node, jayess_html_buffer *buffer, int preserve_comments, int pretty, int depth) {
    const char *type;
    if (node == NULL || buffer->failed) {
        return;
    }
    type = jayess_value_as_string(jayess_value_get_member(node, "type"));
    if (type == NULL) {
        return;
    }
    if (strcmp(type, "document") == 0 || strcmp(type, "fragment") == 0) {
        jayess_html_serialize_children(node, buffer, preserve_comments, pretty, depth);
        return;
    }
	if (strcmp(type, "text") == 0) {
		jayess_html_buffer_append_cstr(buffer, jayess_value_as_string(jayess_value_get_member(node, "value")));
		return;
	}
	if (strcmp(type, "doctype") == 0) {
		const char *value = jayess_value_as_string(jayess_value_get_member(node, "value"));
		jayess_html_buffer_append_cstr(buffer, "<!doctype");
		if (value != NULL && value[0] != '\0') {
			jayess_html_buffer_append_cstr(buffer, " ");
			jayess_html_buffer_append_cstr(buffer, value);
		}
		jayess_html_buffer_append_cstr(buffer, ">");
		return;
	}
	if (strcmp(type, "comment") == 0) {
        if (!preserve_comments) {
            return;
        }
        jayess_html_buffer_append_cstr(buffer, "<!--");
        jayess_html_buffer_append_cstr(buffer, jayess_value_as_string(jayess_value_get_member(node, "value")));
        jayess_html_buffer_append_cstr(buffer, "-->");
        return;
    }
    if (strcmp(type, "element") == 0) {
        jayess_html_serialize_element(node, buffer, preserve_comments, pretty, depth);
    }
}

static jayess_value *jayess_html_parse_internal(jayess_value *input_value, const char *document_type) {
    const char *input = jayess_expect_string(input_value, "jayess_html_parse");
    char *owned_input;
    jayess_html_parser parser;
    jayess_array *children;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    owned_input = jayess_html_strdup(input);
    if (owned_input == NULL) {
        return jayess_value_undefined();
    }
    parser.input = owned_input;
    parser.length = strlen(input);
    parser.pos = 0;
    parser.error = NULL;
    children = jayess_html_parse_children(&parser, NULL);
    if (parser.error != NULL) {
        jayess_html_free_partial_array(children);
        free(owned_input);
        jayess_throw_named_error("HTMLParseError", parser.error);
        return jayess_value_undefined();
    }
    {
        jayess_value *document = jayess_html_make_document_like(document_type, children);
        jayess_html_set_span(document, &parser, 0, parser.pos);
        free(owned_input);
        return document;
    }
}

jayess_value *jayess_html_tokenize(jayess_value *input_value) {
    const char *input = jayess_expect_string(input_value, "jayess_html_tokenize");
    char *owned_input;
    jayess_html_parser parser;
    jayess_array *tokens;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    owned_input = jayess_html_strdup(input);
    if (owned_input == NULL) {
        return jayess_value_undefined();
    }
    parser.input = owned_input;
    parser.length = strlen(input);
    parser.pos = 0;
    parser.error = NULL;
    tokens = jayess_array_new();
    while (parser.pos < parser.length) {
        if (jayess_html_has_prefix(&parser, "<!--")) {
            size_t token_start = parser.pos;
            size_t value_start;
            size_t value_end;
            char *comment_text;
            parser.pos += 4;
            value_start = parser.pos;
            while (parser.pos + 2 < parser.length && !jayess_html_has_prefix(&parser, "-->")) {
                parser.pos++;
            }
            if (!jayess_html_has_prefix(&parser, "-->")) {
                parser.error = "unterminated HTML comment";
                break;
            }
            value_end = parser.pos;
            comment_text = jayess_html_copy_range(parser.input, value_start, value_end);
            parser.pos += 3;
            jayess_array_push_value(tokens, jayess_html_make_comment_token(comment_text != NULL ? comment_text : "", &parser, token_start, parser.pos));
            free(comment_text);
            continue;
        }
        if (jayess_html_has_prefix_ci(&parser, "<!DOCTYPE")) {
            size_t token_start = parser.pos;
            size_t value_start;
            size_t value_end;
            char *doctype_text;
            parser.pos += 9;
            jayess_html_skip_ws(&parser);
            value_start = parser.pos;
            while (parser.pos < parser.length && jayess_html_peek(&parser) != '>') {
                parser.pos++;
            }
            if (jayess_html_peek(&parser) != '>') {
                parser.error = "unterminated HTML doctype";
                break;
            }
            value_end = parser.pos;
            doctype_text = jayess_html_copy_range(parser.input, value_start, value_end);
            parser.pos++;
            jayess_array_push_value(tokens, jayess_html_make_doctype_token(doctype_text != NULL ? doctype_text : "", &parser, token_start, parser.pos));
            free(doctype_text);
            continue;
        }
        if (jayess_html_has_prefix(&parser, "</")) {
            size_t token_start = parser.pos;
            char *tag_name;
            parser.pos += 2;
            jayess_html_skip_ws(&parser);
            tag_name = jayess_html_parse_name(&parser);
            if (tag_name == NULL) {
                parser.error = "expected HTML closing tag name";
                break;
            }
            jayess_html_skip_ws(&parser);
            if (jayess_html_peek(&parser) != '>') {
                free(tag_name);
                parser.error = "expected > after HTML closing tag";
                break;
            }
            parser.pos++;
            jayess_array_push_value(tokens, jayess_html_make_end_tag_token(tag_name, &parser, token_start, parser.pos));
            free(tag_name);
            continue;
        }
        if (jayess_html_peek(&parser) == '<') {
            size_t token_start = parser.pos;
            char *tag_name;
            jayess_object *attributes;
            jayess_array *attribute_order;
            int self_closing = 0;
            parser.pos++;
            tag_name = jayess_html_parse_name(&parser);
            if (tag_name == NULL) {
                parser.error = "expected HTML tag name";
                break;
            }
            attributes = jayess_object_new();
            attribute_order = jayess_array_new();
            while (parser.pos < parser.length) {
                char *attr_name;
                char *attr_value;
                jayess_html_skip_ws(&parser);
                if (jayess_html_has_prefix(&parser, "/>")) {
                    self_closing = 1;
                    parser.pos += 2;
                    break;
                }
                if (jayess_html_peek(&parser) == '>') {
                    parser.pos++;
                    break;
                }
                attr_name = jayess_html_parse_name(&parser);
                if (attr_name == NULL) {
                    jayess_html_free_partial_object(attributes);
                    jayess_html_free_partial_array(attribute_order);
                    free(tag_name);
                    parser.error = "expected HTML attribute name";
                    break;
                }
                jayess_array_push_value(attribute_order, jayess_value_from_string(attr_name));
                jayess_html_skip_ws(&parser);
                if (jayess_html_peek(&parser) == '=') {
                    parser.pos++;
                    jayess_html_skip_ws(&parser);
                    attr_value = jayess_html_parse_attr_value(&parser);
                    if (attr_value == NULL) {
                        free(attr_name);
                        jayess_html_free_partial_object(attributes);
                        jayess_html_free_partial_array(attribute_order);
                        free(tag_name);
                        break;
                    }
                    jayess_object_set_value(attributes, attr_name, jayess_value_from_string(attr_value));
                    free(attr_value);
                } else {
                    jayess_object_set_value(attributes, attr_name, jayess_value_from_bool(1));
                }
                free(attr_name);
            }
            if (parser.error != NULL) {
                break;
            }
            jayess_array_push_value(tokens, jayess_html_make_start_tag_token(tag_name, attributes, attribute_order, self_closing, &parser, token_start, parser.pos));
            free(tag_name);
            continue;
        }
        {
            size_t token_start = parser.pos;
            char *text;
            while (parser.pos < parser.length && parser.input[parser.pos] != '<') {
                parser.pos++;
            }
            text = jayess_html_copy_range(parser.input, token_start, parser.pos);
            if (text != NULL && text[0] != '\0') {
                jayess_array_push_value(tokens, jayess_html_make_text_token(text, &parser, token_start, parser.pos));
            }
            free(text);
        }
    }
    if (parser.error != NULL) {
        jayess_html_free_partial_array(tokens);
        free(owned_input);
        jayess_throw_named_error("HTMLParseError", parser.error);
        return jayess_value_undefined();
    }
    free(owned_input);
    return jayess_value_from_array(tokens);
}

jayess_value *jayess_html_parse_document(jayess_value *input_value) {
    return jayess_html_parse_internal(input_value, "document");
}

jayess_value *jayess_html_parse_fragment(jayess_value *input_value) {
    return jayess_html_parse_internal(input_value, "fragment");
}

jayess_value *jayess_html_serialize(jayess_value *node, jayess_value *options) {
    jayess_html_buffer buffer;
    int preserve_comments = jayess_html_serialize_preserve_comments(options);
    int pretty = jayess_html_serialize_pretty(options);
    int minify = jayess_html_serialize_minify(options);
    if (minify) {
        pretty = 0;
    }
    buffer.data = NULL;
    buffer.length = 0;
    buffer.capacity = 0;
    buffer.failed = 0;
    jayess_html_serialize_value(node, &buffer, preserve_comments, pretty, 0);
    if (buffer.failed) {
        free(buffer.data);
        jayess_throw_named_error("HTMLSerializeError", "failed to serialize HTML AST");
        return jayess_value_undefined();
    }
    if (buffer.data == NULL) {
        return jayess_value_from_string("");
    }
    {
        jayess_value *result = jayess_value_from_string(buffer.data);
        free(buffer.data);
        return result;
    }
}

jayess_value *jayess_html_create_element(jayess_value *tag_name_value, jayess_value *attributes_value, jayess_value *children_value) {
    const char *tag_name = jayess_expect_string(tag_name_value, "jayess_html_create_element");
    jayess_object *attributes = attributes_value != NULL && jayess_value_kind_of(attributes_value) == JAYESS_VALUE_OBJECT ? jayess_value_as_object(attributes_value) : jayess_object_new();
    jayess_array *children = children_value != NULL && jayess_value_kind_of(children_value) == JAYESS_VALUE_ARRAY ? jayess_value_as_array(children_value) : jayess_array_new();
    jayess_array *attribute_order = jayess_array_new();
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (attributes_value != NULL && jayess_value_kind_of(attributes_value) == JAYESS_VALUE_OBJECT) {
        jayess_array *keys = jayess_object_keys(attributes);
        int index;
        for (index = 0; index < jayess_array_length(keys); index++) {
            jayess_array_push_value(attribute_order, jayess_array_get(keys, index));
        }
    }
    return jayess_html_make_element(tag_name, attributes, attribute_order, children, 0);
}

jayess_value *jayess_html_create_text(jayess_value *value) {
    const char *text = jayess_expect_string(value, "jayess_html_create_text");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    return jayess_html_make_text(text);
}

jayess_value *jayess_html_create_comment(jayess_value *value) {
    const char *text = jayess_expect_string(value, "jayess_html_create_comment");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    return jayess_html_make_comment(text);
}

jayess_value *jayess_html_set_attribute(jayess_value *node, jayess_value *name_value, jayess_value *value) {
    const char *name = jayess_expect_string(name_value, "jayess_html_set_attribute");
    jayess_object *attributes;
    jayess_array *attribute_order;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (!jayess_html_is_element(node)) {
        jayess_throw_named_error("HTMLNodeError", "setAttribute requires an element node");
        return jayess_value_undefined();
    }
    attributes = jayess_value_as_object(jayess_value_get_member(node, "attributes"));
    attribute_order = jayess_value_as_array(jayess_value_get_member(node, "attributeOrder"));
    jayess_object_set_value(attributes, name, value);
    if (!jayess_html_attribute_order_contains(attribute_order, name)) {
        jayess_array_push_value(attribute_order, jayess_value_from_string(name));
    }
    return node;
}

jayess_value *jayess_html_remove_attribute(jayess_value *node, jayess_value *name_value) {
    const char *name = jayess_expect_string(name_value, "jayess_html_remove_attribute");
    jayess_object *attributes;
    jayess_array *attribute_order;
    jayess_array *filtered;
    int index;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (!jayess_html_is_element(node)) {
        jayess_throw_named_error("HTMLNodeError", "removeAttribute requires an element node");
        return jayess_value_undefined();
    }
    attributes = jayess_value_as_object(jayess_value_get_member(node, "attributes"));
    attribute_order = jayess_value_as_array(jayess_value_get_member(node, "attributeOrder"));
    jayess_object_delete(attributes, name);
    filtered = jayess_array_new();
    for (index = 0; index < jayess_array_length(attribute_order); index++) {
        jayess_value *entry = jayess_array_get(attribute_order, index);
        const char *entry_name = jayess_value_as_string(entry);
        if (entry_name == NULL || strcmp(entry_name, name) != 0) {
            jayess_array_push_value(filtered, entry);
        }
    }
    jayess_value_set_member(node, "attributeOrder", jayess_value_from_array(filtered));
    return node;
}

jayess_value *jayess_html_append_child(jayess_value *node, jayess_value *child) {
    jayess_array *children = jayess_html_expect_children(node, "appendChild requires a node with children");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    jayess_array_push_value(children, child);
    return node;
}

jayess_value *jayess_html_remove_child(jayess_value *node, jayess_value *index_value) {
    jayess_array *children = jayess_html_expect_children(node, "removeChild requires a node with children");
    int index = (int) jayess_value_to_number(index_value);
    jayess_array *filtered;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (index < 0 || index >= jayess_array_length(children)) {
        jayess_throw_named_error("HTMLNodeError", "removeChild index out of range");
        return jayess_value_undefined();
    }
    filtered = jayess_html_remove_index(children, index);
    jayess_value_set_member(node, "children", jayess_value_from_array(filtered));
    return node;
}

jayess_value *jayess_html_replace_child(jayess_value *node, jayess_value *index_value, jayess_value *child) {
    jayess_array *children = jayess_html_expect_children(node, "replaceChild requires a node with children");
    int index = (int) jayess_value_to_number(index_value);
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (index < 0 || index >= jayess_array_length(children)) {
        jayess_throw_named_error("HTMLNodeError", "replaceChild index out of range");
        return jayess_value_undefined();
    }
    jayess_array_set_value(children, index, child);
    return node;
}

jayess_value *jayess_html_clone_node(jayess_value *node) {
    return jayess_html_clone_node_value(node);
}

jayess_value *jayess_html_walk_depth_first(jayess_value *node) {
    jayess_array *result = jayess_array_new();
    jayess_html_walk_collect(node, result);
    return jayess_value_from_array(result);
}

jayess_value *jayess_html_find_by_tag(jayess_value *node, jayess_value *tag_name_value) {
    const char *tag_name = jayess_expect_string(tag_name_value, "jayess_html_find_by_tag");
    jayess_array *result;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    result = jayess_array_new();
    jayess_html_find_by_tag_collect(node, tag_name, result);
    return jayess_value_from_array(result);
}

jayess_value *jayess_html_matches_selector(jayess_value *node, jayess_value *selector_value) {
    const char *selector_text = jayess_expect_string(selector_value, "jayess_html_matches_selector");
    jayess_html_selector selector;
    jayess_value *ancestors[1];
    int matched;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (!jayess_html_parse_selector(selector_text, &selector)) {
        jayess_throw_named_error("HTMLSelectorError", "invalid selector");
        return jayess_value_undefined();
    }
    ancestors[0] = node;
    matched = jayess_html_matches_selector_steps(ancestors, 1, &selector, selector.count - 1, 0);
    jayess_html_selector_free(&selector);
    return jayess_value_from_bool(matched);
}

jayess_value *jayess_html_query_selector_all(jayess_value *node, jayess_value *selector_value) {
    const char *selector_text = jayess_expect_string(selector_value, "jayess_html_query_selector_all");
    jayess_html_selector selector;
    jayess_array *walk;
    jayess_array *result;
    jayess_value **ancestors;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (!jayess_html_parse_selector(selector_text, &selector)) {
        jayess_throw_named_error("HTMLSelectorError", "invalid selector");
        return jayess_value_undefined();
    }
    walk = jayess_array_new();
    jayess_html_walk_collect(node, walk);
    ancestors = (jayess_value **) calloc((size_t) jayess_array_length(walk), sizeof(jayess_value *));
    result = jayess_array_new();
    if (ancestors == NULL) {
        jayess_html_selector_free(&selector);
        jayess_throw_named_error("HTMLSelectorError", "failed to allocate selector traversal state");
        return jayess_value_undefined();
    }
    jayess_html_query_selector_collect(node, &selector, result, ancestors, 0);
    free(ancestors);
    jayess_html_selector_free(&selector);
    return jayess_value_from_array(result);
}
